+    params.providerConfig.noOutputTimeoutMs,
+    timeoutMs,
+  );
+  const maxOutputBytes = normalizePositiveInt(
+    params.providerConfig.maxOutputBytes,
+    DEFAULT_EXEC_MAX_OUTPUT_BYTES,
+  );
